#include<bits/stdc++.h>
using namespace std;
const int N=200005;
int n,m,t[4*N];
map<int,int> mmap;
void push_up(int u)
{
	t[u]=max(t[u*2],t[u*2+1]);
}
void add(int u,int l,int r,int x,int y,int k)
{
	if(l>y||r<x) return ;
	if(l>=x&&r<=y)
	{
		t[u]+=k;
		return ;
	}
	int mid=(l+r)>>1;
	add(u*2,l,mid,x,y,k);
	add(u*2+1,mid+1,r,x,y,k);
	push_up(u);
}
int maxx(int u,int l,int r,int x,int y)
{
	if(l>=x&&r<=y) return t[u];
	int mid=(l+r)/2;
	int ans=0;
	if(x<=mid) ans=max(ans,maxx(u*2,l,mid,x,y));
	if(y>mid) ans=max(ans,maxx(u*2+1,mid+1,r,x,y));
	return ans;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int y,r;
		cin>>y>>r;
		add(1,1,n,i,i,r);
		mmap[y]=i;
	}
	cin>>m;
	for(int i=1;i<=m;i++)
	{
		int x,y;
		cin>>y>>x;
		if(y>=x)
		{
			cout<<"false\n";
			continue;
		}
		if(!mmap.count(x)&&!mmap.count(y))
		{
			cout<<"maybe\n";
			continue;
		}
		map<int,int>::iterator itx=mmap.lower_bound(x),ity=mmap.lower_bound(y);
		if(ity==mmap.end())
		{
			cout<<"maybe\n";
			continue;
		}
		int x1=(itx==mmap.end())?n+1:itx->second;
		int y1=ity->second;
		if(!mmap.count(y)) y1--;
		int y2=maxx(1,1,n,y1,y1),x2=(x1==n+1)?-1:maxx(1,1,n,x1,x1);
		int mmax=((y1+1)<=(x1-1))?maxx(1,1,n,y1+1,x1-1):0;
		bool flag;
		if(!mmap.count(y)) flag=mmax<x2;
		else if(!mmap.count(x)) flag=mmax<y2;
		else flag=((y2>=x2)&&(x2>mmax));
		string s[]={"false","true"};
		string s1[]={"false","maybe"};
		if(y1-x1==y-x&&mmap.count(y)&&mmap.count(x)) cout<<s[flag]<<'\n';
		else cout<<s1[flag]<<'\n';
	}
	return 0;
}
